// The Great Harvester: Rips jars out of AARs so kotlinc can read them
tasks.register("harvestDeps") {
    doLast {
        def dest = file("build/harvested_libs")
        dest.deleteDir()
        dest.mkdirs()

        configurations.releaseRuntimeClasspath.resolvedConfiguration.resolvedArtifacts.each { artifact ->
            def file = artifact.file
            if (file.name.endsWith(".jar")) {
                copy {
                    from file
                    into dest
                }
            } else if (file.name.endsWith(".aar")) {
                copy {
                    from zipTree(file).matching { include "classes.jar" }
                    into dest
                    rename "classes.jar", "${artifact.moduleVersion.id.group}-${artifact.name}-${artifact.moduleVersion.id.version}.jar"
                }
            }
        }
        println "✅ Harvested ${dest.listFiles().size()} libraries into the Armory."
    }
}

